import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
// Import all your page components
import AuthorityPage from './pages/Authority';
import BinPage from './pages/Bin';
import DriverPage from './pages/Driver';
import UserPage from './pages/User';
import VehiclePage from './pages/Vehicle';

function App() {
      const appStyles = {
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #2c3e50 0%, #3498db 50%, #e74c3c 100%)',
        fontFamily: "'Georgia', 'Times New Roman', serif",
      };

  const containerStyles = {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '20px',
    minHeight: 'calc(100vh - 80px)',
  };

      const welcomeStyles = {
        textAlign: 'center',
        color: 'white',
        fontSize: '2.2rem',
        fontWeight: '400',
        marginTop: '40px',
        textShadow: '0 2px 4px rgba(0,0,0,0.5)',
        background: 'rgba(0,0,0,0.3)',
        padding: '30px',
        borderRadius: '10px',
        border: '2px solid rgba(255,255,255,0.3)',
        boxShadow: '0 4px 15px rgba(0,0,0,0.3)',
      };

  return (
    <div style={appStyles}>
      <Router>
        <Navbar />
        <div style={containerStyles}>
          <Routes>
            {/* Default landing page */}
                <Route path="/" element={
                  <div style={welcomeStyles}>
                    <h1>📚 Student DBMS Project</h1>
                    <p style={{ fontSize: '1.1rem', marginTop: '15px', opacity: 0.9, fontStyle: 'italic' }}>
                      Database Management System for Waste Collection Operations
                    </p>
                    <div style={{ 
                      marginTop: '25px', 
                      padding: '15px', 
                      background: 'rgba(255,255,255,0.1)', 
                      borderRadius: '8px',
                      fontSize: '0.9rem',
                      textAlign: 'left',
                      maxWidth: '600px',
                      margin: '25px auto 0'
                    }}>
                      <p><strong>Student:</strong> Anup Kumar Jena</p>
                      <p><strong>Course:</strong> Database Management Systems</p>
                      <p><strong>Technology Stack:</strong> React.js, Node.js, MySQL, Express.js</p>
                      <p><strong>Features:</strong> CRUD Operations, Foreign Key Constraints, Data Validation</p>
                    </div>
                    <div style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                      gap: '15px',
                      marginTop: '30px'
                    }}>
                      <div style={{ 
                        background: 'rgba(255,255,255,0.15)', 
                        padding: '15px', 
                        borderRadius: '8px',
                        border: '1px solid rgba(255,255,255,0.2)'
                      }}>
                        <h4 style={{ margin: '0 0 8px 0', fontSize: '1rem' }}>👥 Authority</h4>
                        <p style={{ margin: '0', fontSize: '0.85rem', opacity: 0.9 }}>Manage authorities</p>
                      </div>
                      <div style={{ 
                        background: 'rgba(255,255,255,0.15)', 
                        padding: '15px', 
                        borderRadius: '8px',
                        border: '1px solid rgba(255,255,255,0.2)'
                      }}>
                        <h4 style={{ margin: '0 0 8px 0', fontSize: '1rem' }}>🚛 Vehicle</h4>
                        <p style={{ margin: '0', fontSize: '0.85rem', opacity: 0.9 }}>Track vehicles</p>
                      </div>
                      <div style={{ 
                        background: 'rgba(255,255,255,0.15)', 
                        padding: '15px', 
                        borderRadius: '8px',
                        border: '1px solid rgba(255,255,255,0.2)'
                      }}>
                        <h4 style={{ margin: '0 0 8px 0', fontSize: '1rem' }}>🗂️ Bin</h4>
                        <p style={{ margin: '0', fontSize: '0.85rem', opacity: 0.9 }}>Monitor bins</p>
                      </div>
                      <div style={{ 
                        background: 'rgba(255,255,255,0.15)', 
                        padding: '15px', 
                        borderRadius: '8px',
                        border: '1px solid rgba(255,255,255,0.2)'
                      }}>
                        <h4 style={{ margin: '0 0 8px 0', fontSize: '1rem' }}>👤 User</h4>
                        <p style={{ margin: '0', fontSize: '0.85rem', opacity: 0.9 }}>Manage users</p>
                      </div>
                      <div style={{ 
                        background: 'rgba(255,255,255,0.15)', 
                        padding: '15px', 
                        borderRadius: '8px',
                        border: '1px solid rgba(255,255,255,0.2)'
                      }}>
                        <h4 style={{ margin: '0 0 8px 0', fontSize: '1rem' }}>🚗 Driver</h4>
                        <p style={{ margin: '0', fontSize: '0.85rem', opacity: 0.9 }}>Handle drivers</p>
                      </div>
                    </div>
                  </div>
                } />

            {/* Routes for each entity management page */}
            <Route path="/authority" element={<AuthorityPage />} />
            <Route path="/bin" element={<BinPage />} />
            <Route path="/driver" element={<DriverPage />} />
            <Route path="/user" element={<UserPage />} />
            <Route path="/vehicle" element={<VehiclePage />} />
          </Routes>
        </div>
      </Router>
    </div>
  );
}

export default App;
